const SYSTEMS = {
  bazi: BAZI,
  ziwei: ZIWEI,
  astro: ASTRO,
  hd: HD,
  qizheng: QIZHENG,
  maya: MAYA,
  lifepath: LIFEPATH,
  fuling: FULING,
};

module.exports = function handler(req, res) {
  // CORS
  var origin = req.headers.origin || '';
  var allowed = ['https://hourlightkey.com', 'https://www.hourlightkey.com'];
  if (allowed.indexOf(origin) > -1) res.setHeader('Access-Control-Allow-Origin', origin);
  res.setHeader('Access-Control-Allow-Methods', 'GET, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.status(200).end();

  var system = req.query.system || '';
  var relation = req.query.relation || '';

  // action=list → 列出所有可用的系統和關係
  if (req.query.action === 'list') {
    var available = {};
    Object.keys(SYSTEMS).forEach(function(sys) {
      var rels = Object.keys(SYSTEMS[sys]);
      if (rels.length > 0) available[sys] = rels;
    });
    return res.status(200).json({ available: available });
  }

  // 檢查參數
  if (!system) return res.status(400).json({ error: '需要 system 參數' });

  var sysData = SYSTEMS[system];
  if (!sysData || Object.keys(sysData).length === 0) {
    return res.status(404).json({ error: system + ' 尚未建置' });
  }

  // 不帶 relation → 回傳該系統全部關係（前端一次拿完快取）
  if (!relation) return res.status(200).json(sysData);

  var relData = sysData[relation];
  if (!relData) {
    return res.status(404).json({ error: system + ' 的 ' + relation + ' 尚未建置' });
  }

  return res.status(200).json(relData);
};

